import ldap

def find_user_by_username(username, ldap_server, ldap_port, ldap_user, ldap_password):
    """
    Searches for a user in an LDAP directory by their username.

    Args:
        username: The username to search for.
        ldap_server: The LDAP server hostname or IP address.
        ldap_port: The LDAP server port.
        ldap_user: The LDAP administrator username.
        ldap_password: The LDAP administrator password.

    Returns:
        The LDAP entry for the user if found, None otherwise.
    """

    # Create an LDAP connection
    ldap_connection = ldap.initialize(f"ldap://{ldap_server}:{ldap_port}")

    # Bind to the LDAP server
    ldap_connection.simple_bind(ldap_user, ldap_password)

    # Search for the user by username
    search_filter = f"uid={username}"
    search_result = ldap_connection.search(
        search_base="dc=example,dc=com",
        search_filter=search_filter,
        search_scope=ldap.SCOPE_SUBTREE
    )

    # Close the LDAP connection
    ldap_connection.unbind()

    # Return the LDAP entry for the user if found, None otherwise
    if search_result:
        return search_result[0][1]
    else:
        return None